import{_ as a,o as r,c as s,ag as t}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Scorecards","description":"Automatically evaluate every service against engineering standards and produce a letter grade from A to F.","frontmatter":{"title":"Scorecards","description":"Automatically evaluate every service against engineering standards and produce a letter grade from A to F."},"headers":[],"relativePath":"portals/devx/scorecards.md","filePath":"portals/devx/scorecards.md"}'),o={name:"portals/devx/scorecards.md"};function i(c,e,d,n,l,h){return r(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="scorecards" tabindex="-1">Scorecards <a class="header-anchor" href="#scorecards" aria-label="Permalink to &quot;Scorecards&quot;">​</a></h1><p><strong>Route:</strong> <code>/scorecards</code> · <strong>Edition:</strong> Community+</p><p>Scorecards automatically evaluate every service in the catalog against a set of engineering standards — documentation, SLOs, on-call coverage, security, and more — and produce a letter grade (A–F).</p><h2 id="how-scoring-works" tabindex="-1">How scoring works <a class="header-anchor" href="#how-scoring-works" aria-label="Permalink to &quot;How scoring works&quot;">​</a></h2><p>Each scorecard rule checks a specific attribute of a service:</p><ul><li>Does the service have a runbook?</li><li>Are SLOs defined?</li><li>Is the service assigned to a team?</li><li>Does the service have a repository URL?</li><li>Are environments configured?</li></ul><p>Each rule carries a weight. The final score is a weighted average, mapped to a letter grade.</p><h2 id="leaderboard" tabindex="-1">Leaderboard <a class="header-anchor" href="#leaderboard" aria-label="Permalink to &quot;Leaderboard&quot;">​</a></h2><p>The scorecards page shows a ranked list of all services, sorted by score. This encourages teams to keep their service metadata complete and up-to-date.</p><h2 id="service-scorecard-detail" tabindex="-1">Service scorecard detail <a class="header-anchor" href="#service-scorecard-detail" aria-label="Permalink to &quot;Service scorecard detail&quot;">​</a></h2><p>Click any service to see its individual rule breakdown — which rules pass, which fail, and what the specific gap is. Use this to prioritise improvements.</p><h2 id="rules-management" tabindex="-1">Rules management <a class="header-anchor" href="#rules-management" aria-label="Permalink to &quot;Rules management&quot;">​</a></h2><p>Admins can view and customise the built-in rules under <strong>Portal Config → Scorecard Rules</strong>. New rules can be added with custom weights.</p>',13)])])}const m=a(o,[["render",i]]);export{p as __pageData,m as default};
